def decompose_documents(tokenized_docs, bucket_lengths=(128, 256, 512, 1024, 2048)):
    buckets = {L: [] for L in bucket_lengths}
    for doc in tokenized_docs:
        n = len(doc)
        for L in bucket_lengths:
            for start in range(0, n - L + 1, L):
                # never concatenate across documents
                buckets[L].append(doc[start:start + L])
    return buckets

def sample_curriculum_bucket(buckets, step, total_steps):
    lengths = sorted([L for L, seqs in buckets.items() if seqs])
    max_idx = max(0, int((len(lengths) - 1) * step / max(1, total_steps - 1)))
    active_lengths = lengths[:max_idx + 1]
    return active_lengths[-1]
